import { useMemo } from "react";
import { Link } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import SEO from "@/components/ui/SEO";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { Skeleton, SkeletonChart } from "@/components/ui/skeleton";
import { Reveal, RevealStagger, StaggerItem } from "@/components/landing/motion";
import {
  TrendingUp, TrendingDown, DollarSign, ShoppingCart, Percent,
  Search, Heart, Bell, ArrowUpRight, Sparkles,
} from "lucide-react";
import Breadcrumb from "@/components/ui/Breadcrumb";
import {
  ResponsiveContainer, BarChart, PieChart,
  Bar, Pie, XAxis, YAxis, Tooltip, Cell,
} from "recharts";

const COLORS = ["#10b981", "#3b82f6", "#f59e0b", "#ef4444", "#8b5cf6", "#06b6d4", "#ec4899"];

function CustomTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-bg-deep/95 border border-white/15 rounded-lg px-3 py-2 shadow-2xl">
      <div className="font-mono text-[10px] text-zinc-400 mb-1">{label}</div>
      {payload.map((entry, i) => (
        <div key={i} className="font-mono text-xs text-white tabular">
          <span className="inline-block w-2 h-2 rounded-full mr-1.5 align-middle" style={{ background: entry.color }} />
          {entry.name || ""}: {fmt(entry.value)}
        </div>
      ))}
    </div>
  );
}

function SummaryCard({ label, value, sub, icon: Icon, trend }) {
  return (
    <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
      <div className="flex items-center justify-between mb-2">
        <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">{label}</div>
        {Icon && <Icon className="w-4 h-4 text-zinc-500" />}
      </div>
      <div className="text-3xl font-heading font-bold tabular-nums">{value}</div>
      {sub && (
        <div className={`flex items-center gap-1 mt-1 text-[11px] ${trend === "up" ? "text-emerald-400" : trend === "down" ? "text-red-400" : "text-zinc-400"}`}>
          {trend === "up" && <TrendingUp className="w-3 h-3" />}
          {trend === "down" && <TrendingDown className="w-3 h-3" />}
          {sub}
        </div>
      )}
    </div>
  );
}

function ChartCard({ icon: Icon, title, children, className = "" }) {
  return (
    <div className={`bg-white/[0.02] border border-white/10 rounded-lg p-5 ${className}`}>
      <div className="flex items-center gap-2 mb-4">
        {Icon && <Icon className="w-4 h-4 text-emerald-400" />}
        <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">{title}</div>
      </div>
      {children}
    </div>
  );
}

export default function Dashboard() {
  const { market, loading, error } = useMarket();

  const metrics = useMemo(() => {
    if (!market?.rows) return null;
    const stats = market.stats;
    const totalCount = stats.totalItems;
    const priced = stats.pricedItems;
    const healthPct = Math.round((priced / totalCount) * 100) || 0;
    const confidencePct = Math.round((stats.highConfidence / priced) * 100) || 0;
    const rising = stats.risingItems;

    const trendCounts = { up: 0, down: 0, stable: 0 };
    const deals = [];
    const overpriced = [];

    market.rows.forEach(r => {
      if (r.trend === "up") trendCounts.up++;
      else if (r.trend === "down") trendCounts.down++;
      else trendCounts.stable++;

      // Outlier detection logic
      if (r.median > 0 && r.iqrLow > 0 && r.iqrHigh > r.iqrLow) {
        const spread = (r.iqrHigh - r.iqrLow) / r.iqrLow;
        if (spread >= 0.25) {
          const ratio = (r.median - r.iqrLow) / (r.iqrHigh - r.iqrLow);
          if (ratio <= 0.15) deals.push(r);
          else if (ratio >= 0.85) overpriced.push(r);
        }
      }
    });

    const sentiment = trendCounts.up > trendCounts.down ? "Bullish" : trendCounts.down > trendCounts.up ? "Bearish" : "Neutral";
    const sentimentColor = sentiment === "Bullish" ? "text-emerald-400" : sentiment === "Bearish" ? "text-red-400" : "text-zinc-400";

    const priceRanges = [
      { range: "<10k", min: 0, max: 10000, count: 0 },
      { range: "10k-100k", min: 10000, max: 100000, count: 0 },
      { range: "100k-1M", min: 100000, max: 1000000, count: 0 },
      { range: "1M-10M", min: 1000000, max: 10000000, count: 0 },
      { range: "10M-100M", min: 10000000, max: 100000000, count: 0 },
      { range: ">100M", min: 100000000, count: 0 },
    ];

    market.rows.forEach(row => {
      if (row.median > 0) {
        if (row.median < 10000) priceRanges[0].count++;
        else if (row.median < 100000) priceRanges[1].count++;
        else if (row.median < 1000000) priceRanges[2].count++;
        else if (row.median < 10000000) priceRanges[3].count++;
        else if (row.median < 100000000) priceRanges[4].count++;
        else priceRanges[5].count++;
      }
    });

    const confidenceDistribution = [
      { name: "High", value: market.rows.filter(r => r.confidence === "high").length },
      { name: "Good", value: market.rows.filter(r => r.confidence === "good").length },
      { name: "Fair", value: market.rows.filter(r => r.confidence === "fair").length },
      { name: "Low", value: market.rows.filter(r => r.confidence === "low").length },
      { name: "Unreliable", value: market.rows.filter(r => r.confidence === "unreliable").length },
    ];

    return {
      priced, healthPct, confidencePct, rising,
      trendCounts, priceDistributionData: priceRanges,
      confidenceDistribution, sentiment, sentimentColor,
      deals: deals.sort((a, b) => a.median - b.median).slice(0, 5),
      overpriced: overpriced.sort((a, b) => b.median - a.median).slice(0, 5),
    };
  }, [market]);

  if (loading.market || !metrics) {
    return (
      <div className="min-h-screen bg-bg-base text-white">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <Skeleton className="h-4 w-32 mb-4" />
            <Skeleton className="h-12 w-96 mb-8" />
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="bg-white/[0.02] border border-white/10 rounded-lg p-5 space-y-3">
                  <Skeleton className="h-3 w-20" />
                  <Skeleton className="h-8 w-24" />
                  <Skeleton className="h-3 w-16" />
                </div>
              ))}
            </div>
            <SkeletonChart />
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const {
    priceDistributionData, confidenceDistribution, sentiment, sentimentColor,
    deals, overpriced,
    priced, healthPct, confidencePct, rising, trendCounts,
  } = metrics;

  return (
    <div data-testid="dashboard-page" className="min-h-screen bg-bg-base text-white font-body">
      <SEO title="Dashboard" description="Global market analytics, price trends, and trading volume." />
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <Breadcrumb
              items={[
                { label: "Home", href: "/" },
                { label: "Market Dashboard" },
              ]}
              color="text-emerald-400"
            />
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
              <div>
                <h1 className="font-heading text-5xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
                  Market <span className="text-emerald-400">Insights</span>
                </h1>
                <p className="mt-4 text-zinc-400 font-mono text-xs uppercase tracking-widest">
                  Real-time economic pulse · {market.stats.lastUpdated}
                </p>
              </div>
              
              <div className="flex items-center gap-3 shrink-0">
                <Link to="/lookup" className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-[10px] px-5 py-3 rounded-sm transition-all active:scale-95 shadow-lg shadow-emerald-500/20">
                  <Search className="w-3.5 h-3.5" /> Look up item
                </Link>
                <div className="flex items-center gap-1.5 p-1 bg-white/[0.03] border border-white/10 rounded-sm">
                  <Link to="/favorites" title="Favorites" className="p-2 text-zinc-400 hover:text-white transition-colors">
                    <Heart className="w-4 h-4" />
                  </Link>
                  <Link to="/alerts" title="Alerts" className="p-2 text-zinc-400 hover:text-white transition-colors">
                    <Bell className="w-4 h-4" />
                  </Link>
                </div>
              </div>
            </div>
          </Reveal>

          {/* Top Bento Row: KPIs + Sentiment */}
          <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
            <RevealStagger className="md:col-span-2 lg:col-span-3 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <StaggerItem>
                <SummaryCard label="Market Coverage" value={`${healthPct}%`} sub={`${priced} priced items`} icon={ShoppingCart} />
              </StaggerItem>
              <StaggerItem>
                <SummaryCard label="Price Volatility" value={rising + trendCounts.down} sub={`${rising} rising · ${trendCounts.down} falling`} icon={TrendingUp} />
              </StaggerItem>
              <StaggerItem>
                <SummaryCard label="Avg Confidence" value={`${confidencePct}%`} sub={`${market.stats.highConfidence} high-conf items`} icon={Percent} />
              </StaggerItem>
            </RevealStagger>
            
            <Reveal delay={0.2} className="h-full">
              <div className="bg-emerald-500/5 border border-emerald-500/20 rounded-lg p-5 h-full flex flex-col justify-between">
                <div className="flex items-center justify-between mb-4">
                  <div className="text-[10px] uppercase tracking-wider text-emerald-500/70 font-mono">Market Sentiment</div>
                  <Sparkles className="w-4 h-4 text-emerald-500/50" />
                </div>
                <div>
                  <div className={`text-4xl font-heading font-black tracking-tight ${sentimentColor}`}>{sentiment}</div>
                  <div className="text-[11px] text-zinc-500 mt-2 font-mono">
                    Trend ratio: {(trendCounts.up / (trendCounts.down || 1)).toFixed(1)}x
                  </div>
                </div>
                <div className="mt-4 h-1.5 bg-white/5 rounded-full overflow-hidden flex">
                  <div className="bg-emerald-500 h-full" style={{ width: `${(trendCounts.up / (trendCounts.up + trendCounts.down + trendCounts.stable)) * 100}%` }} />
                  <div className="bg-zinc-700 h-full" style={{ width: `${(trendCounts.stable / (trendCounts.up + trendCounts.down + trendCounts.stable)) * 100}%` }} />
                  <div className="bg-red-500 h-full" style={{ width: `${(trendCounts.down / (trendCounts.up + trendCounts.down + trendCounts.stable)) * 100}%` }} />
                </div>
              </div>
            </Reveal>
          </div>

          {/* Main Analytics Row */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
            {/* Price Distribution - Large */}
            <Reveal className="lg:col-span-2">
              <ChartCard icon={DollarSign} title="Price Distribution (Active Listings)">
                <div className="h-[320px] mt-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={priceDistributionData}>
                      <XAxis dataKey="range" tick={{ fill: "#6b7280", fontSize: 10, fontFamily: "Geist Mono" }} axisLine={false} tickLine={false} />
                      <YAxis tick={{ fill: "#6b7280", fontSize: 10, fontFamily: "Geist Mono" }} axisLine={false} tickLine={false} />
                      <Tooltip content={<CustomTooltip />} cursor={{ fill: "rgba(255,255,255,0.03)" }} />
                      <Bar dataKey="count" fill="#10b981" radius={[4, 4, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </ChartCard>
            </Reveal>

            {/* Outliers Feed */}
            <Reveal delay={0.1}>
              <div className="space-y-4 h-full flex flex-col">
                <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5 flex-1">
                  <div className="flex items-center justify-between mb-6">
                    <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Market Outliers</div>
                    <Link to="/listings?sort=deal" className="text-[9px] uppercase tracking-widest text-emerald-400 hover:underline">View All</Link>
                  </div>
                  
                  <div className="space-y-4">
                    <div>
                      <div className="text-[9px] uppercase tracking-widest text-zinc-600 font-mono mb-3">Potential Deals</div>
                      <div className="space-y-2">
                        {deals.map(item => (
                          <Link key={item.key} to={`/item/${encodeURIComponent(item.key)}`} className="flex items-center justify-between group">
                            <div className="text-xs text-zinc-300 group-hover:text-emerald-400 transition-colors truncate mr-2">{item.name}</div>
                            <div className="text-xs font-mono text-emerald-500 shrink-0">{fmt(item.median)}</div>
                          </Link>
                        ))}
                      </div>
                    </div>
                    
                    <div className="pt-4 border-t border-white/5">
                      <div className="text-[9px] uppercase tracking-widest text-zinc-600 font-mono mb-3">Overpriced Items</div>
                      <div className="space-y-2">
                        {overpriced.map(item => (
                          <Link key={item.key} to={`/item/${encodeURIComponent(item.key)}`} className="flex items-center justify-between group">
                            <div className="text-xs text-zinc-300 group-hover:text-red-400 transition-colors truncate mr-2">{item.name}</div>
                            <div className="text-xs font-mono text-red-500 shrink-0">{fmt(item.median)}</div>
                          </Link>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </Reveal>
          </div>

          {/* Secondary Charts Row */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-8">
            <Reveal>
              <ChartCard icon={Percent} title="Confidence Spread">
                <div className="h-48 mt-2">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={confidenceDistribution}
                        innerRadius={60}
                        outerRadius={80}
                        paddingAngle={5}
                        dataKey="value"
                      >
                        {confidenceDistribution.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip content={<CustomTooltip />} />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </ChartCard>
            </Reveal>

            <Reveal delay={0.05}>
              <ChartCard icon={ShoppingCart} title="Category Density">
                <div className="space-y-3 mt-2">
                  {market.categoryBreakdown.slice(0, 5).map((c) => (
                    <div key={c.name} className="flex items-center gap-3">
                      <div className="w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: c.color }} />
                      <div className="flex-1 text-[11px] font-mono text-zinc-300 truncate">{c.name}</div>
                      <div className="text-right shrink-0">
                        <div className="text-[11px] font-mono text-white">{c.value} <span className="text-zinc-500 ml-1">({c.pct}%)</span></div>
                      </div>
                    </div>
                  ))}
                </div>
              </ChartCard>
            </Reveal>

            <Reveal delay={0.1}>
              <ChartCard icon={TrendingDown} title="Trend Analysis">
                <div className="space-y-6 mt-4">
                  <div className="flex items-end justify-between">
                    <div className="text-[10px] text-zinc-500 font-mono uppercase">Bullish / Bearish Ratio</div>
                    <div className="text-xl font-bold text-white">{(trendCounts.up / (trendCounts.down || 1)).toFixed(2)}</div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-mono uppercase">
                      <span className="text-emerald-400">Rising ({trendCounts.up})</span>
                      <span className="text-red-400">Falling ({trendCounts.down})</span>
                    </div>
                    <div className="h-1 bg-white/5 rounded-full overflow-hidden flex">
                      <div className="bg-emerald-500" style={{ width: `${(trendCounts.up / (trendCounts.up + trendCounts.down)) * 100}%` }} />
                      <div className="bg-red-500" style={{ width: `${(trendCounts.down / (trendCounts.up + trendCounts.down)) * 100}%` }} />
                    </div>
                  </div>
                </div>
              </ChartCard>
            </Reveal>
          </div>

          {/* Top Movers - Expanded */}
          <Reveal className="mb-12">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <ArrowUpRight className="w-4 h-4 text-emerald-400" />
                <h2 className="text-sm font-heading font-bold uppercase tracking-widest">Market Movers</h2>
              </div>
              <Link to="/listings" className="text-[10px] uppercase tracking-[0.2em] text-zinc-500 hover:text-white transition-colors">Full Market List →</Link>
            </div>
            
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              {market.topMovers.slice(0, 8).map((item) => (
                <Link
                  key={item.key}
                  to={`/item/${encodeURIComponent(item.key)}`}
                  className="group bg-white/[0.02] border border-white/10 rounded p-4 hover:bg-emerald-500/[0.03] hover:border-emerald-500/30 transition-all active:scale-[0.98]"
                >
                  <div className="flex justify-between items-start mb-2">
                    <div className="text-xs font-bold text-white group-hover:text-emerald-400 transition-colors truncate pr-2">{item.name}</div>
                    <span className={item.trend === "rising" ? "text-emerald-400" : item.trend === "falling" ? "text-red-400" : "text-zinc-400"}>
                      {item.trend === "rising" ? "↑" : item.trend === "falling" ? "↓" : "—"}
                    </span>
                  </div>
                  <div className="flex items-end justify-between">
                    <div className="text-sm font-mono font-bold text-zinc-300">{fmt(item.medianRaw)}</div>
                    <div className="text-[9px] text-zinc-500 font-mono uppercase">{item.conf} conf</div>
                  </div>
                </Link>
              ))}
            </div>
          </Reveal>

          {error.market && (
            <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-4 text-red-300 text-sm mt-8">
              {error.market}
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}

